def check_config(dbdriver, dbtype, dbhost, dbuser, dbpasswd, testdb):
    """Verify the database settings work for connecting."""
    global DBDRIVER, DBTYPE, DBHOST, DBUSER, DBPASSWD, TESTDB, DBSCHEMA, SQL_FILE
    DBDRIVER = dbdriver
    DBTYPE = dbtype
    DBHOST = dbhost
    DBUSER = dbuser
    DBPASSWD = dbpasswd
    TESTDB = testdb

    if not DBDRIVER or not DBTYPE or not DBUSER:
        # No point going any further...
        raise MissingExternalDependencyError("Incomplete BioSQL test settings")

    # Check the database driver is installed:
    if SYSTEM == "Java":
        try:
            if DBDRIVER in ["MySQLdb"]:
                import com.mysql.jdbc.Driver  # noqa: F401
            elif DBDRIVER in ["psycopg2", "pgdb"]:
                import org.postgresql.Driver  # noqa: F401
        except ImportError:
            message = f"Install the JDBC driver for {DBTYPE} to use BioSQL "
            raise MissingExternalDependencyError(message) from None
    else:
        try:
            __import__(DBDRIVER)
        except ImportError:
            if DBDRIVER in ["MySQLdb"]:
                message = (
                    "Install MySQLdb or mysqlclient if you want to use %s with BioSQL "
                    % (DBTYPE)
                )
            else:
                message = f"Install {DBDRIVER} if you want to use {DBTYPE} with BioSQL "
            raise MissingExternalDependencyError(message) from None

    try:
        if DBDRIVER in ["sqlite3"]:
            server = BioSeqDatabase.open_database(driver=DBDRIVER, db=TESTDB)
        else:
            server = BioSeqDatabase.open_database(
                driver=DBDRIVER, host=DBHOST, user=DBUSER, passwd=DBPASSWD
            )
        server.close()
        del server
    except Exception as e:
        message = f"Connection failed, check settings if you plan to use BioSQL: {e}"
        raise MissingExternalDependencyError(message) from None

    DBSCHEMA = "biosqldb-" + DBTYPE + ".sql"
    SQL_FILE = os.path.join(os.getcwd(), "BioSQL", DBSCHEMA)

    if not os.path.isfile(SQL_FILE):
        message = f"Missing SQL schema file: {SQL_FILE}"
        raise MissingExternalDependencyError(message)

def create_database():
    """Delete any existing BioSQL test DB, then (re)create an empty BioSQL DB.

    Returns TESTDB name which will change for for SQLite.
    """
    if DBDRIVER in ["sqlite3"]:
        global TESTDB
        if os.path.exists(TESTDB):
            try:
                os.remove(TESTDB)
            except Exception:
                time.sleep(1)
                try:
                    os.remove(TESTDB)
                except Exception:
                    # Seen this with PyPy 2.1 (and older) on Windows -
                    # which suggests an open handle still exists?
                    print(f"Could not remove {TESTDB!r}")
        # Now pick a new filename - just in case there is a stale handle
        # (which might be happening under Windows...)
        TESTDB = temp_db_filename()
    else:
        _do_db_cleanup()

    # now open a connection to load the database
    server = BioSeqDatabase.open_database(
        driver=DBDRIVER, user=DBUSER, passwd=DBPASSWD, host=DBHOST, db=TESTDB
    )
    try:
        server.load_database_sql(SQL_FILE)
        server.commit()
        server.close()
    except Exception:
        # Failed, but must close the handle...
        server.close()
        raise

    return TESTDB

def destroy_database():
    """Delete any temporary BioSQL sqlite3 database files."""
    if DBDRIVER in ["sqlite3"]:
        if os.path.exists(TESTDB):
            os.remove(TESTDB)

def test_localds_zero_score_segments_symmetric(self):
    """Test if alignment is independent on direction of sequence."""
    aligns1 = pairwise2.align.localds(
        "CWHISLKM", "CWHGISGLKM", self.blosum62, -11, -1
    )
    aligns2 = pairwise2.align.localds(
        "MKLSIHWC", "MKLGSIGHWC", self.blosum62, -11, -1
    )
    self.assertEqual(len(aligns1), len(aligns2))

def test_blosum62(self):
    """Test localds with blosum62."""
    self.assertEqual(1, self.blosum62[("K", "Q")])
    self.assertEqual(4, self.blosum62[("A", "A")])
    self.assertEqual(8, self.blosum62[("H", "H")])
    alignments = pairwise2.align.localds(
        "VKAHGKKV", "FQAHCAGV", self.blosum62, -4, -4
    )
    for a in alignments:
        self.assertEqual(
            pairwise2.format_alignment(*a), "2 KAH\n  .||\n2 QAH\n  Score=13\n"
        )

def test_empty_result(self):
    """Return no alignment."""
    self.assertEqual(pairwise2.align.localxx("AT", "GC"), [])

def test_separate_penalize_end_gaps(self):
    """Test alignment where end-gaps are differently penalized."""
    align = pairwise2.align.globalms(
        "AT", "AGG", 1.0, -0.5, -1.75, -0.25, penalize_end_gaps=(True, False)
    )
    self.assertEqual(align[0], ("A--T", "AGG-", -1.0, 0, 4))

def test_recover_alignments(self):
    """One possible start position in local alignment is not a match."""
    self.assertEqual(len(pairwise2.align.localxx("AC", "GA")), 1)

